import React, { useState, useEffect, useRef } from 'react';

const App = () => {
  const [bootPhase, setBootPhase] = useState(0);
  const [terminalReady, setTerminalReady] = useState(false);
  const [commandHistory, setCommandHistory] = useState([]);
  const [currentInput, setCurrentInput] = useState('');
  const [output, setOutput] = useState([]);
  const terminalRef = useRef(null);

  const fileSystem = {
    '~': {
      type: 'dir',
      contents: ['tech-stack.txt', 'experience.log', 'projects', 'contact', 'about.txt', 'services.txt']
    },
    '~/projects': {
      type: 'dir',
      contents: ['ecommerce-platform', 'ios-fitness app', 'android-banking']
    },
    '~/contact': {
      type: 'dir',
      contents: ['github', 'linkedin', 'email']
    },
    '~/github': {
      type: 'file',
      content: 'https://github.com/Hamzah-Mohandes'
    },
    '~/linkedin': {
      type: 'file',
      content: 'https://www.linkedin.com/in/hamzah-mohandeszadeh-5542a0160/?skipRedirect=true'
    },
    '~/email': {
      type: 'file',
      content: 'mailto:hamzah@example.com'
    },
    '~/tech-stack.txt': {
      type: 'file',
      content: `Rust в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€ 92%
JavaScript в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€ 95%
Swift в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€ 90%
Kotlin в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€ 88%
Node.js в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€ 92%
React в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€ 94%
Jetpack Compose в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€ 85%
SwiftUI в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€ 87%
MongoDB в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€ 82%
Firebase в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€в–€ 84%`
    },
    '~/experience.log': {
      type: 'file',
      content: `2022 - Present: Full Stack Developer @ Tech Company
Building scalable web and mobile applications`
    },
    '~/about.txt': {
      type: 'file',
      content: `Hamzah Mohandeszadeh (Zenu)
Full Stack Developer | iOS & Android Specialist
рџ“Ќ Hamburg, Germany
вњ“ Available for freelance projects`
    },
    '~/services.txt': {
      type: 'file',
      content: `в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ
                        MY SERVICES
в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ

рџљЂ WEB DEVELOPMENT
   вЂў Full-stack web applications
   вЂў E-commerce platforms
   вЂў Progressive Web Apps (PWA)
   Starting from: в‚¬2,500

рџ“± MOBILE DEVELOPMENT  
   вЂў iOS apps (Swift/SwiftUI)
   вЂў Android apps (Kotlin/Jetpack Compose)
   вЂў Cross-platform solutions
   Starting from: в‚¬3,000

вљЎ BACKEND & API
   вЂў RESTful APIs & GraphQL
   вЂў Database design & optimization
   вЂў Cloud infrastructure (AWS, Firebase)
   Starting from: в‚¬1,500

рџЋЁ UI/UX DESIGN
   вЂў Modern interface design
   вЂў User experience optimization
   вЂў Design systems & components
   Starting from: в‚¬1,000

в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ
рџ’ј READY TO START YOUR PROJECT?
   Type "hire" or email: hamzah@example.com
в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ`
    }
  };

  const bootSequence = [
    { text: 'BIOS Version 2.15.1', delay: 100 },
    { text: 'CPU: Quantum Core i9 @ 5.2GHz', delay: 150 },
    { text: 'Memory: 64GB DDR5-6400MHz', delay: 150 },
    { text: 'Loading kernel...', delay: 300 },
    { text: '[ OK ] Mounting root filesystem', delay: 200 },
    { text: '[ OK ] Starting network', delay: 200 },
    { text: '[ OK ] Initializing display subsystem', delay: 200 },
    { text: '[ OK ] Loading user profile', delay: 200 },
    { text: 'System ready.', delay: 300 }
  ];

  useEffect(() => {
    let timeout;
    const runBootSequence = () => {
      if (bootPhase < bootSequence.length) {
        setOutput(prev => [...prev, { type: 'boot', text: bootSequence[bootPhase].text }]);
        timeout = setTimeout(() => {
          setBootPhase(prev => prev + 1);
        }, bootSequence[bootPhase].delay);
      } else {
        setTerminalReady(true);
        setOutput(prev => [...prev, { type: 'system', text: 'в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ' }]);
        setOutput(prev => [...prev, { type: 'system', text: '  WELCOME TO ZENU TERMINAL v2.0' }]);
        setOutput(prev => [...prev, { type: 'system', text: 'в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ' }]);
        setOutput(prev => [...prev, { type: 'system', text: '' }]);
        setOutput(prev => [...prev, { type: 'clickable', text: 'рџ’ј LOOKING TO HIRE? Click here or type "hire"', command: 'hire' }]);
        setOutput(prev => [...prev, { type: 'system', text: '' }]);
        setOutput(prev => [...prev, { type: 'system', text: '  QUICK START GUIDE:' }]);
        setOutput(prev => [...prev, { type: 'clickable', text: '  вЂў help - See all available commands', command: 'help' }]);
        setOutput(prev => [...prev, { type: 'clickable', text: '  вЂў ls - List all available files', command: 'ls' }]);
        setOutput(prev => [...prev, { type: 'clickable', text: '  вЂў whoami - Learn about the developer', command: 'whoami' }]);
        setOutput(prev => [...prev, { type: 'clickable', text: '  вЂў neofetch - See system information', command: 'neofetch' }]);
        setOutput(prev => [...prev, { type: 'system', text: '' }]);
        setOutput(prev => [...prev, { type: 'system', text: '  AVAILABLE FILES (click to open):' }]);
        setOutput(prev => [...prev, { type: 'clickable', text: '  вЂў services.txt в­ђ - Services & pricing', command: 'cat services.txt' }]);
        setOutput(prev => [...prev, { type: 'clickable', text: '  вЂў tech-stack.txt - Skills and technologies', command: 'cat tech-stack.txt' }]);
        setOutput(prev => [...prev, { type: 'clickable', text: '  вЂў experience.log - Work experience', command: 'cat experience.log' }]);
        setOutput(prev => [...prev, { type: 'clickable', text: '  вЂў about.txt - About the developer', command: 'cat about.txt' }]);
        setOutput(prev => [...prev, { type: 'clickable', text: '  вЂў github - GitHub profile', command: 'cat github' }]);
        setOutput(prev => [...prev, { type: 'clickable', text: '  вЂў linkedin - LinkedIn profile', command: 'cat linkedin' }]);
        setOutput(prev => [...prev, { type: 'clickable', text: '  вЂў email - Contact email', command: 'cat email' }]);
        setOutput(prev => [...prev, { type: 'system', text: '' }]);
        setOutput(prev => [...prev, { type: 'system', text: 'в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ' }]);
      }
    };
    runBootSequence();
    return () => clearTimeout(timeout);
  }, [bootPhase]);

  // Matrix rain effect
  useEffect(() => {
    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d');
    canvas.id = 'matrix-canvas';
    canvas.style.position = 'fixed';
    canvas.style.top = '0';
    canvas.style.left = '0';
    canvas.style.width = '100%';
    canvas.style.height = '100%';
    canvas.style.zIndex = '1';
    canvas.style.opacity = '0.15';
    document.body.appendChild(canvas);

    const matrix = document.getElementById('matrix');
    if (matrix) {
      matrix.appendChild(canvas);
    }

    const resizeCanvas = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
    };
    resizeCanvas();
    window.addEventListener('resize', resizeCanvas);

    const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789@#$%^&*()';
    const fontSize = 14;
    const columns = canvas.width / fontSize;
    const drops = Array(Math.floor(columns)).fill(1);

    const drawMatrix = () => {
      ctx.fillStyle = 'rgba(0, 0, 0, 0.05)';
      ctx.fillRect(0, 0, canvas.width, canvas.height);
      ctx.fillStyle = '#0F0';
      ctx.font = fontSize + 'px monospace';

      for (let i = 0; i < drops.length; i++) {
        const text = chars[Math.floor(Math.random() * chars.length)];
        ctx.fillText(text, i * fontSize, drops[i] * fontSize);

        if (drops[i] * fontSize > canvas.height && Math.random() > 0.975) {
          drops[i] = 0;
        }
        drops[i]++;
      }
    };

    const matrixInterval = setInterval(drawMatrix, 50);

    return () => {
      clearInterval(matrixInterval);
      window.removeEventListener('resize', resizeCanvas);
      if (canvas.parentNode) {
        canvas.parentNode.removeChild(canvas);
      }
    };
  }, []);

  useEffect(() => {
    if (terminalRef.current) {
      terminalRef.current.scrollTop = terminalRef.current.scrollHeight;
    }
  }, [output]);

  const executeCommand = (cmd) => {
    const trimmedCmd = cmd.trim().toLowerCase();
    const parts = cmd.trim().split(' ');
    let command = parts[0].toLowerCase();
    let args = parts.slice(1);

    // Auto-correct: if they type just a filename, treat it as "cat filename"
    if (fileSystem[`~/${command}`] && !['help', 'ls', 'cat', 'whoami', 'clear', 'date', 'uname', 'neofetch', 'hire'].includes(command)) {
      args = [command];
      command = 'cat';
    }

    setCommandHistory(prev => [...prev, cmd]);
    setOutput(prev => [...prev, { type: 'input', text: `zenu@dev:~$ ${cmd}` }]);

